:root {
  --card-bg: #ffffff;
  --header-bg: #1e1b4b;
  --avatar-bg: #4f46e5;
  --avatar-text: #ffffff;
  --avatar-border: #ffffff;
  --badge-bg: #dcfce7;
  --badge-text: #16a34a;
  --name-color: #1e1b4b;
  --role-color: #6b7280;
  --divider-color: #e5e7eb;
  --stat-value-color: #1e1b4b;
  --stat-label-color: #9ca3af;
  --btn-primary-bg: #4f46e5;
  --btn-primary-text: #ffffff;
  --btn-secondary-bg: #f3f4f6;
  --btn-secondary-text: #374151;
  --card-radius: 16px;
  --card-border: #e5e7eb;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
}

.profile-card {
  background-color: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: var(--card-radius);
  width: 300px;
  overflow: hidden;
}

.profile-header {
  background-color: var(--header-bg);
  padding: 28px 24px 20px;
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
}

.avatar {
  width: 72px;
  height: 72px;
  border-radius: 50%;
  background-color: var(--avatar-bg);
  border: 3px solid var(--avatar-border);
  display: flex;
  align-items: center;
  justify-content: center;
}

.avatar-initials {
  color: var(--avatar-text);
  font-size: 22px;
  font-weight: 700;
  line-height: 1;
}

.status-badge {
  background-color: var(--badge-bg);
  color: var(--badge-text);
  font-size: 12px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 20px;
}

.profile-body {
  padding: 16px 24px 20px;
}

.profile-name {
  margin: 0 0 4px;
  font-size: 20px;
  font-weight: 700;
  color: var(--name-color);
  line-height: 1.2;
}

.profile-role {
  margin: 0;
  font-size: 14px;
  color: var(--role-color);
  font-weight: 400;
}

.divider {
  height: 1px;
  background-color: var(--divider-color);
  margin: 16px 0;
}

.stats-row {
  display: flex;
  justify-content: space-between;
}

.stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.stat-value {
  font-size: 20px;
  font-weight: 700;
  color: var(--stat-value-color);
  line-height: 1;
}

.stat-label {
  font-size: 12px;
  color: var(--stat-label-color);
  font-weight: 400;
}

.profile-footer {
  padding: 0 24px 20px;
  display: flex;
  gap: 10px;
}

.btn {
  flex: 1;
  padding: 10px 0;
  border: none;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
}

.btn-primary {
  background-color: var(--btn-primary-bg);
  color: var(--btn-primary-text);
}

.btn-secondary {
  background-color: var(--btn-secondary-bg);
  color: var(--btn-secondary-text);
}
